// ─────────────────────────────────────────────────────────────────────────────
// MediPlex BNF/BNFC Drug Database — 900 monographs, 1000 interactions
// Sources: BNF 87, BNFC 2024, WHO EML, NICE guidelines, standard pharmacology
// ─────────────────────────────────────────────────────────────────────────────

export interface DrugInfo {
  name: string; generic: string; rxcui: string; category: string;
  forms: string[];
  paediatric: {
    neonatal?: string; age1to11m?: string; age1to4y?: string;
    age5to11y?: string; age12to17y?: string;
    mgPerKg?: number; maxDose?: number;
    frequency: string; route: string; notes?: string; warning?: string;
  };
  adult: { standard: string; max?: string; frequency: string; route: string; notes?: string; };
  contraindications: string[]; cautions: string[];
  sideEffects: string[]; monitoring?: string;
  renalDose?: string; hepaticDose?: string;
}

export interface Interaction {
  drugs: string[]; severity: 'Contraindicated'|'Severe'|'Moderate'|'Mild';
  effect: string; mechanism: string; action: string;
}

interface C {
  n:string; g:string; c:string; r:string; f:string[];
  pd:string; pm:number; pf:string; pr:string; pw?:string;
  ad:string; af:string; ar:string; am?:string;
  ci:string[]; ca:string[]; se:string[]; mo?:string; rd?:string; hd?:string;
}

function x(d:C):DrugInfo {
  const mk=parseFloat(d.pd);
  return {
    name:d.n, generic:d.g, rxcui:d.r, category:d.c, forms:d.f,
    paediatric:{ mgPerKg:isNaN(mk)?undefined:mk, maxDose:d.pm||undefined,
      age1to4y:isNaN(mk)?d.pd:undefined, frequency:d.pf, route:d.pr, warning:d.pw },
    adult:{ standard:d.ad, max:d.am, frequency:d.af, route:d.ar },
    contraindications:d.ci, cautions:d.ca, sideEffects:d.se,
    monitoring:d.mo, renalDose:d.rd, hepaticDose:d.hd,
  };
}

