// ─── ONCOLOGY SUPPORTIVE CARE ─────────────────────────────────────────────────
const ONCOLOGY_SUPPORTIVE_RAW:C[]=[
  {n:'Filgrastim (G-CSF / Neupogen)',g:'filgrastim',c:'Oncology Supportive - G-CSF (neutropenia)',r:'5162',f:['SC/IV injection 300mcg/0.5ml, 480mcg/0.8ml','Lenograstim, Pegfilgrastim (long-acting)'],
   pd:'5mcg/kg/day SC (mobilisation/chemotherapy)',pm:0,pf:'Once daily SC',pr:'SC/IV',pw:'Granulocyte-colony stimulating factor — stimulates neutrophil production. Chemotherapy-induced neutropenia (prophylaxis/treatment of febrile neutropenia). Stem cell mobilisation (peripheral blood). Bone pain (most common SE — splenic pain/rupture rarely). Start 24h after last chemotherapy dose. Pegfilgrastim (Neulasta) — single dose per cycle (pegylated — longer acting). Biosimilars available. Sickle cell: splenic sequestration risk.',
   ad:'Chemotherapy support: 5mcg/kg/day SC (round to vial size — 300/480mcg). Start day 2-5 post-chemo. Mobilisation: 10mcg/kg/day x4-5 days.',af:'Once daily SC',ar:'SC (or IV infusion)',am:'10mcg/kg/day (mobilisation)',
   ci:['Myeloid malignancy (relative — stimulates growth)','Concomitant chemotherapy and radiotherapy'],ca:['Bone pain (analgesia)','Splenic rupture (rare — left upper quadrant pain)','ARDS (pulmonary infiltrates)','Sickle cell disease'],
   se:['Bone pain (most common)','Splenomegaly/splenic rupture','Thrombocytopenia (rebound)','ARDS (rare)','Capillary leak syndrome'],mo:'FBC. Spleen size if pain. LFTs. Uric acid (mobilisation).'},
  {n:'Epoetin alfa / darbepoetin alfa (EPO)',g:'epoetin alfa',c:'Oncology Supportive - Erythropoiesis-stimulating agent',r:'4736',f:['SC/IV prefilled syringe (various strengths)','Darbepoetin alfa (Aranesp) — longer acting'],
   pd:'Not routinely licensed for paediatric chemotherapy anaemia',pm:0,pf:'Weekly or 3-weekly (depending on agent)',pr:'SC/IV',pw:'Erythropoiesis-stimulating agents (ESAs). Chemotherapy-related anaemia (Hb < 10 — symptom-driven, not prophylactic). Renal anaemia (chronic kidney disease). NOT for iron deficiency anaemia (check iron first). Correct iron deficiency before/during ESA treatment. MHRA: increased risk of venous thromboembolism and tumour progression in some cancers. Target Hb 10-12 g/dL (not higher — VTE/mortality risk). Erythropoietin response requires iron, B12, folate.',
   ad:'Chemotherapy anaemia: epoetin alfa 150 units/kg SC 3x/week or 40,000 units SC weekly. Darbepoetin: 500mcg SC 3-weekly.',af:'Weekly/3-weekly',ar:'SC',am:'Per protocol and Hb target',
   ci:['Uncontrolled hypertension','Pure red cell aplasia (ESA-related)','Haemoglobin > 12 g/dL'],ca:['VTE risk (thromboprophylaxis)','Hypertension (monitor and treat)','Iron supplementation (concurrent)','Tumour progression (certain solid tumours)'],
   se:['Hypertension','VTE (DVT/PE)','Pure red cell aplasia (antibody-mediated — rare)','Flu-like symptoms','Headache'],mo:'Hb (2-4 weekly — target 10-12). BP. Iron studies. Ferritin. Transferrin saturation.'},
  {n:'Ondansetron (chemotherapy CINV)',g:'ondansetron',c:'Oncology Supportive - 5-HT3 antagonist (CINV)',r:'9584',f:['IV 2mg/ml ampoule','Oral 4mg/8mg tablets','Zydis orodispersible 4mg/8mg'],
   pd:'0.15mg/kg IV (max 8mg)',pm:32,pf:'Every 8-12h',pr:'IV/Oral',pw:'5-HT3 antagonist — first line antiemetic for chemotherapy-induced nausea and vomiting (CINV). Acute CINV (0-24h post-chemo). Used in combination with dexamethasone (± NK1 antagonist for highly emetogenic chemo — e.g. cisplatin). QT prolongation. Headache (most common). Constipation. Serotonin syndrome risk. IV: give slowly over 15 min. Highly emetogenic chemotherapy (cisplatin) requires triple therapy: 5-HT3 + dex + NK1 antagonist (aprepitant/fosaprepitant).',
   ad:'CINV prophylaxis: 8mg IV 30 min pre-chemo; then 8mg IV/PO every 8h for 24h. Oral: 8mg 1-2h before, then 8mg every 8h for up to 5 days.',af:'8-12 hourly',ar:'IV/Oral',am:'32mg/day',
   ci:['Congenital long QT','Concurrent apomorphine'],ca:['QT prolongation (correct electrolytes first)','Serotonin syndrome (concurrent serotonergic drugs)'],
   se:['Headache','Constipation','QT prolongation','Serotonin syndrome (rare)','Transaminase elevation'],mo:'QTc. Electrolytes (correct hypokalaemia/hypoMg first). Nausea control.'},
  {n:'Aprepitant / fosaprepitant (NK1 antagonist)',g:'aprepitant',c:'Oncology Supportive - NK1 receptor antagonist (CINV)',r:'57817',f:['Aprepitant: 80mg/125mg capsules','Fosaprepitant (IV prodrug): 150mg powder'],
   pd:'Limited paediatric data — specialist protocol',pm:0,pf:'Oral day 1 (125mg), days 2-3 (80mg)',pr:'Oral/IV',pw:'Neurokinin 1 (NK1) antagonist — blocks substance P. Highly emetogenic chemotherapy (cisplatin, anthracyclines — CINV triple therapy with 5-HT3 + dexamethasone). Reduces acute AND delayed CINV (NK1 responsible for delayed 24-120h nausea). CYP3A4 inhibitor — reduces dexamethasone dose (halve dex when giving aprepitant). Multiple drug interactions (CYP3A4). Fosaprepitant = IV prodrug (single 150mg dose pre-chemo).',
   ad:'Aprepitant: 125mg oral day 1 (1h pre-chemo), 80mg days 2-3 morning. Dexamethasone dose reduced 50% when co-administering. Fosaprepitant: 150mg IV single dose 30 min pre-chemo.',af:'Days 1-3 per cycle',ar:'Oral/IV',am:'125mg day 1; 80mg days 2-3',
   ci:['Concurrent pimozide/terfenadine/astemizole','CYP3A4-dependent narrow therapeutic index drugs'],ca:['CYP3A4 interactions (warfarin, phenytoin)','Dexamethasone dose reduction needed (CYP3A4 inhibition)','Hepatic impairment'],
   se:['Hiccups','Fatigue','Constipation','Headache','LFT elevation','Drug interactions (CYP3A4)'],mo:'CINV control. Drug interactions check. LFTs.'},
  {n:'Metoclopramide (CINV/nausea)',g:'metoclopramide hydrochloride',c:'Oncology Supportive - Dopamine antagonist/prokinetic (nausea)',r:'8673',f:['IV/IM 5mg/ml ampoule','Oral 10mg tablets'],
   pd:'NOT <1y. 1-18y: 0.1mg/kg per dose (max 0.5mg/kg/day). Only 3 days max.',pm:0,pf:'3 times daily',pr:'IV/IM/Oral',pw:'D2 antagonist — antiemetic/prokinetic. MHRA 2013: restrict to short-term use (≤5 days) — tardive dyskinesia, extrapyramidal effects (younger/elderly particularly at risk). Not for chronic use (gastroparesis — domperidone preferred). Acute dystonia: procyclidine 5mg IV/IM. Avoid in bowel obstruction (prokinetic — could perforate). Parkinsons disease (contraindicated — D2 antagonism worsens).',
   ad:'Nausea/vomiting: 10mg IV/IM/oral up to 3 times daily. MAX 5 days. Prokinetic: 10mg 30 min before meals.',af:'8 hourly (max 5 days)',ar:'IV/IM/Oral',am:'30mg/day (max 3 doses)',
   ci:['GI haemorrhage/obstruction/perforation','Phaeochromocytoma','Parkinsons disease','Epilepsy','Prolactinoma'],ca:['Extrapyramidal reactions (young/elderly — higher risk)','Max 5 days (MHRA)','Acute dystonia (procyclidine antidote)','Tardive dyskinesia (long-term)'],
   se:['Extrapyramidal reactions (acute dystonia, akathisia)','Tardive dyskinesia (prolonged use)','Hyperprolactinaemia','Drowsiness','Diarrhoea'],mo:'Extrapyramidal side effects. Prolactin (long-term).'},
  {n:'Haloperidol (intractable nausea/palliative)',g:'haloperidol',c:'Oncology Supportive/Palliative - Antipsychotic/antiemetic',r:'6380',f:['IV/SC/IM 5mg/ml ampoule','Oral 500mcg/1.5mg/5mg/10mg tablets','Oral liquid 1mg/ml','Depot formulations'],
   pd:'Weight-based (specialist)',pm:0,pf:'BD-TDS (oral); continuous SC infusion (palliative)',pr:'Oral/SC/IV/IM',pw:'D2 antagonist (potent). Palliative care antiemetic (particularly opioid-induced nausea, uraemia, raised ICP). Delirium/agitation (palliative). Compatible with many drugs in syringe driver (diamorphine, midazolam). QT prolongation (IV — MHRA warning). Extrapyramidal effects. Neuroleptic malignant syndrome (rare). Used in CSCI (continuous subcutaneous infusion) in palliative care.',
   ad:'Nausea: 0.5-1.5mg SC/oral BD-TDS (palliative). Delirium: 1-5mg SC/IV (acute). CSCI: 5-10mg/24h.',af:'BD-TDS or continuous SC',ar:'Oral/SC/IV',am:'20mg/day',
   ci:['Parkinsons disease (relative)','Dementia with Lewy bodies (severe EPS risk)','QT prolongation/torsades'],ca:['QT prolongation (IV — monitor ECG)','EPS (dystonia/akathisia)','NMS','Falls (elderly)'],
   se:['Extrapyramidal effects','QT prolongation','NMS','Sedation','Postural hypotension','Tardive dyskinesia'],mo:'QTc (IV). Extrapyramidal effects. Sedation level.'},
  {n:'Zoledronic acid (bisphosphonate)',g:'zoledronic acid',c:'Oncology Supportive - IV bisphosphonate (hypercalcaemia/bone mets)',r:'12809',f:['IV infusion 4mg in 100ml (Zometa)','5mg in 100ml (Aclasta — osteoporosis dose)'],
   pd:'Not routinely used (specialist oncology)',pm:0,pf:'IV every 3-4 weeks (oncology)',pr:'IV infusion over 15 min minimum',pw:'Most potent bisphosphonate. Hypercalcaemia of malignancy (HCM — corrected Ca > 2.9 mmol/L). Prevention of skeletal-related events (SREs) in bone metastases (multiple myeloma, breast, prostate). Osteoporosis (annual infusion — Aclasta 5mg). Osteonecrosis of the jaw (ONJ) — dental review before starting; avoid invasive dental procedures. Acute phase reaction (flu-like — first dose). Renal dose adjustment (GFR < 60). Adequate hydration pre-infusion.',
   ad:'HCM: 4mg IV over 15 min (single dose, repeat after 7 days if needed). Bone mets: 4mg IV every 3-4 weeks.',af:'Every 3-4 weeks (bone mets)',ar:'IV infusion (minimum 15 min)',am:'4mg per dose (bone mets/HCM)',
   ci:['GFR < 30 ml/min (relative)','Hypocalcaemia (correct first)','Pregnancy'],ca:['Dental review before starting (ONJ prevention)','Renal function (GFR-adjusted dose)','Hydration (500ml saline pre-infusion)','Calcium and vitamin D supplementation'],
   se:['Acute phase reaction (flu, fever, myalgia — first dose)','Osteonecrosis of jaw (ONJ)','Renal impairment','Hypocalcaemia','Atypical femoral fracture (long-term)'],mo:'Corrected Ca. Renal function (before each dose). LFTs. Jaw symptoms.'},
  {n:'Denosumab (RANKL inhibitor)',g:'denosumab',c:'Oncology Supportive - RANKL inhibitor (bone mets/giant cell tumour)',r:'263494',f:['SC injection 120mg/1.7ml (Xgeva — bone mets)','60mg/1ml (Prolia — osteoporosis)'],
   pd:'Giant cell tumour of bone: skeletally mature adolescents',pm:0,pf:'Monthly SC (bone mets)',pr:'SC',pw:'Monoclonal antibody against RANKL — inhibits osteoclast activity. Prevention of SREs (bone mets — similar efficacy to zoledronic acid; no renal dose adjustment required). Giant cell tumour of bone. Hypercalcaemia of malignancy (refractory). Hypocalcaemia (major SE — calcium and vitamin D supplementation mandatory). ONJ (similar risk to bisphosphonates). Rebound osteoclast activation on discontinuation (\"rebound hypercalcaemia\" in bone mets). Dental review before starting.',
   ad:'Bone mets: 120mg SC every 4 weeks. Giant cell tumour: 120mg SC days 1, 8, 15 of month 1; then monthly.',af:'Monthly SC',ar:'SC',am:'120mg per dose',
   ci:['Hypocalcaemia (correct first)','Pregnancy'],ca:['Calcium + vitamin D supplementation mandatory','Dental review (ONJ)','Hypocalcaemia monitoring','Rebound effect on discontinuation'],
   se:['Hypocalcaemia (most important)','ONJ','Hypophosphataemia','Injection site reactions','Fatigue','Rebound hypercalcaemia (on stopping)'],mo:'Corrected Ca. Phosphate. Vitamin D. Jaw symptoms.'},
  {n:'Rasburicase (uric acid reduction — TLS)',g:'rasburicase',c:'Oncology Supportive - Recombinant uricase (tumour lysis syndrome)',r:'390858',f:['IV infusion 1.5mg/7.5mg vials (reconstitute)'],
   pd:'0.2mg/kg IV once daily for up to 7 days',pm:0,pf:'IV once daily',pr:'IV infusion over 30 min',pw:'Recombinant uricase — converts uric acid to allantoin (soluble, excreted). Tumour lysis syndrome (TLS) prophylaxis and treatment — high-grade lymphoma, leukaemia, bulky disease. Much more effective than allopurinol at rapid uric acid reduction (onset minutes vs days). G6PD deficiency — absolute contraindication (H2O2 produced as byproduct → haemolysis). Anaphylaxis. Expensive — restrict to high-risk TLS. Sample must be kept on ice (ex vivo uric acid degradation invalidates result).',
   ad:'0.2mg/kg IV over 30 min once daily. Duration: until uric acid controlled (usually 3-7 days).',af:'Once daily',ar:'IV infusion',am:'0.2mg/kg/day',
   ci:['G6PD deficiency (haemolysis)','Haemolytic anaemia','Pregnancy','Methaemoglobinaemia'],ca:['G6PD screening before use','Anaphylaxis (resuscitation available)','Sample handling (ice immediately — ex vivo degradation)','Expensive — high-risk TLS only'],
   se:['Anaphylaxis/hypersensitivity','Haemolysis (G6PD deficiency)','Methaemoglobinaemia','Nausea/vomiting','Fever'],mo:'Uric acid. FBC. G6PD screen pre-treatment. LDH (TLS marker).'},
  {n:'Allopurinol (uric acid — gout/TLS prophylaxis)',g:'allopurinol',c:'Oncology Supportive/Rheumatology - Xanthine oxidase inhibitor',r:'602',f:['Oral 100mg/300mg tablets','IV formulation (specialist use)'],
   pd:'TLS prophylaxis: 10mg/kg/day (max 400mg/day)',pm:400,pf:'Once daily (or divided)',pr:'Oral',pw:'Xanthine oxidase inhibitor — prevents uric acid synthesis (doesnt degrade existing urate — slower than rasburicase). Gout prophylaxis (start 2-4 weeks after acute attack resolves — dont start during acute attack; initially worsens by mobilising urate). TLS prophylaxis (low-intermediate risk — start 2-3 days before chemotherapy). DRESS syndrome and Stevens-Johnson syndrome (HLA-B*5801 allele — SE Asian patients — screen). Azathioprine interaction (both metabolised by XO — co-administration → azathioprine toxicity — reduce dose 75%).',
   ad:'Gout: 100mg/day initially, titrate 100-300mg/day (max 900mg). TLS prophylaxis: 300mg/day (start 2 days before chemo). Renal dose reduction (GFR-guided).',af:'Once daily',ar:'Oral',am:'900mg/day',
   ci:['Acute gout attack (start after settled)'],ca:['HLA-B*5801 screening (SE Asian/Han Chinese — NICE guidance — SJS/TEN risk)','Azathioprine/mercaptopurine (reduce dose 75%)','Renal dose reduction','DRESS/SJS/TEN awareness'],
   se:['DRESS syndrome','SJS/TEN (rare — HLA-B*5801)','Rash (maculopapular — common)','GI disturbance','LFT elevation'],mo:'Uric acid. Renal function. LFTs. Rash surveillance.'},
  {n:'Dexamethasone (oncology — cerebral oedema/SCC/antiemetic)',g:'dexamethasone',c:'Oncology Supportive - Corticosteroid (cerebral oedema/SCC/CINV)',r:'3474',f:['IV/IM 4mg/ml','Oral 0.5mg/2mg tablets','Oral solution'],
   pd:'Anti-emetic: 0.15mg/kg IV. Cerebral oedema: specialist weight-based dosing',pm:0,pf:'Variable (once daily to 6-hourly)',pr:'IV/Oral',pw:'Used extensively in oncology: (1) PONV/CINV antiemetic (4-8mg IV). (2) Cerebral oedema — malignant (16mg/day in divided doses IV/oral; titrate down). (3) Spinal cord compression (SCC — 16mg IV loading stat, then 8-16mg/day; NICE guidance on urgent radiotherapy). (4) Symptom control in advanced cancer (appetite, fatigue, pain — low dose). Hyperglycaemia — monitor and treat. No mineralocorticoid effects (unlike prednisolone). GI protection (PPI if long-term). Adrenal suppression (gradual withdrawal if >3 weeks).',
   ad:'CINV: 8-12mg IV pre-chemo (reduce 50% if with aprepitant). Cerebral oedema: 16mg/day (4mg QDS or 8mg BD). SCC: 16mg IV stat then 8-16mg/day.',af:'Variable per indication',ar:'IV/Oral',am:'Guided by indication',
   ci:['Systemic infection (relative)'],ca:['Hyperglycaemia (monitor BM)','GI protection (PPI co-prescribe)','Adrenal suppression (gradual wean)','Mood/psychosis (high dose)','Perianal burning (rapid IV — inject slowly)'],
   se:['Hyperglycaemia','Insomnia','Mood disturbance/psychosis','Immunosuppression','Cushings (prolonged)','Adrenal insufficiency (withdrawal)'],mo:'BM. BP. Weight. Mood.'},
  {n:'Ondansetron + granisetron + palonosetron (5-HT3 class overview)',g:'granisetron/palonosetron',c:'Oncology Supportive - 5-HT3 antagonists (CINV)',r:'5804',f:['Granisetron: 1mg/3mg IV; 1mg/2mg oral','Palonosetron: 250mcg IV (single dose)','Ondansetron: see above'],
   pd:'Specialist oncology protocol — weight-based',pm:0,pf:'Pre-chemotherapy (single or daily doses)',pr:'IV/Oral',pw:'Granisetron: high-emetogenic chemo (IV/oral). Longer half-life than ondansetron (once daily dosing). Palonosetron (Aloxi) — second generation 5-HT3 — strongest binding affinity; prolonged effect (40h half-life); CINV prevention acute AND delayed phases. Single pre-chemo IV dose per cycle. Less QT prolongation than ondansetron. CINV MASCC guidelines: use long-acting (palonosetron) for highly emetogenic regimens.',
   ad:'Granisetron: 1mg IV or 2mg oral pre-chemo. Palonosetron: 250mcg IV 30 min pre-chemo (single dose per cycle).',af:'Once pre-chemo (palonosetron); once daily (granisetron)',ar:'IV/Oral',am:'Per cycle (palonosetron)',
   ci:['Congenital long QT (ondansetron/granisetron — less concern with palonosetron)'],ca:['QT prolongation (less with palonosetron)','Serotonin syndrome risk'],
   se:['Headache','Constipation','QT prolongation (variable by agent)','Fatigue'],mo:'CINV control (NRS). QTc (ondansetron/granisetron). Electrolytes.'},
  {n:'Levomepromazine (nozinan — palliative nausea)',g:'levomepromazine',c:'Oncology Supportive/Palliative - Phenothiazine (nausea/agitation/sedation)',r:'8121',f:['SC/IM/IV 25mg/ml ampoule','Oral 25mg tablets'],
   pd:'Specialist palliative paediatrics',pm:0,pf:'BD-TDS oral; continuous SC infusion (palliative)',pr:'Oral/SC/IV',pw:'Broad-spectrum antiemetic (D2, H1, muscarinic, alpha-1 — wide receptor coverage). Palliative care: intractable nausea/vomiting, terminal agitation/restlessness (combined nausea + sedation in one drug — valuable). CSCI compatible (diamorphine, midazolam, haloperidol). Sedating (significant — counsel). Postural hypotension. QT prolongation. Extrapyramidal effects. Low dose for antiemetic (6.25mg), higher for agitation/sedation (12.5-25mg).',
   ad:'Nausea (palliative): 6.25mg SC/oral BD-TDS. Agitation/sedation: 12.5-25mg SC/CSCI. CSCI: 25-75mg/24h.',af:'BD-TDS or CSCI',ar:'Oral/SC',am:'200mg/day',
   ci:['QT prolongation syndromes','CNS depression'],ca:['Postural hypotension (fall risk)','Sedation (counsel patient/family)','QT prolongation','EPS'],
   se:['Sedation','Postural hypotension','QT prolongation','EPS','Dry mouth','Urinary retention'],mo:'QTc. BP (postural). Sedation level.'},
  {n:'Midazolam CSCI (palliative — agitation/dyspnoea)',g:'midazolam hydrochloride',c:'Oncology Supportive/Palliative - Benzodiazepine (terminal restlessness)',r:'8707',f:['SC/IV ampoule 10mg/2ml, 10mg/5ml, 50mg/10ml'],
   pd:'Specialist palliative paediatrics only',pm:0,pf:'CSCI 24h infusion or intermittent SC',pr:'SC/IV (CSCI)',pw:'Short-acting benzodiazepine. Palliative care: terminal agitation, dyspnoea (reduces anxiety component), seizures. CSCI with diamorphine (two common agents in palliative syringe driver — check compatibility). Amnestic (procedural anxiolysis). Respiratory depression (dyspnoea treatment — deliberate — comfort care). Paradoxical agitation (especially elderly/CNS disease — switch to alternative). Compatibility with many drugs in CSCI (Twycross table). Not for prolonged conscious sedation outside ICU without appropriate monitoring.',
   ad:'Terminal agitation: 2.5-5mg SC PRN; CSCI 10-30mg/24h. Dyspnoea: 2.5mg SC PRN. Seizures: 10mg buccal/SC.',af:'PRN + CSCI 24h',ar:'SC (CSCI)/Buccal/IV',am:'60-80mg/24h CSCI (terminal sedation)',
   ci:['Paradoxical reaction (increase agitation — switch agent)'],ca:['Respiratory depression (intended in palliative setting — comfort care)','Paradoxical agitation','Compatibility check in CSCI'],
   se:['Respiratory depression','Sedation','Paradoxical agitation','Amnesia','Hypotension'],mo:'Comfort and agitation level. Respiratory rate (comfort — not resuscitation target in palliative setting).'},
  {n:'Morphine (palliative — pain/dyspnoea)',g:'morphine sulphate',c:'Oncology Supportive/Palliative - Opioid (cancer pain/dyspnoea)',r:'9073',f:['Oral: Oramorph 10mg/5ml solution; Zomorph SR capsules 10/30/60/100/200mg','SC/IV ampoule (10mg/ml)','Modified release: MST Continus tablets'],
   pd:'Weight-based (0.1-0.2mg/kg oral; 0.05-0.1mg/kg SC)',pm:0,pf:'Oral immediate-release 4-hourly; SR 12-hourly',pr:'Oral/SC/IV/CSCI',pw:'Step 3 WHO analgesic ladder. Cancer pain — titrate dose until pain controlled (no ceiling for cancer pain — dose-limited only by side effects). Dyspnoea (low dose — reduces ventilatory drive and anxiety). CSCI palliative care (morphine or diamorphine). Opioid rotation if poor response or intolerable side effects (switch to oxycodone, hydromorphone, fentanyl). Morphine to diamorphine conversion: divide by 3 (oral to SC diamorphine). Naloxone antidote. Anticipatory prescribing for end-of-life (last days of life — PRN SC doses prescribed in advance).',
   ad:'Opioid-naive: 5mg oral 4-hourly (Oramorph). Breakthrough: 1/6 of total daily dose. SR: total 24h dose divided BD (MST). Titrate by 25-50% if poor control. CSCI: 24h oral dose ÷ 3 (SC diamorphine).',af:'4-hourly immediate release; 12-hourly SR',ar:'Oral/SC/IV/CSCI',am:'No ceiling in cancer pain',
   ci:['Acute respiratory depression','Ileus (relative)'],ca:['Constipation (co-prescribe laxative — senna+docusate)','Nausea (antiemetic)','Drowsiness (initial)','Renal failure (morphine-6-glucuronide accumulation — switch to alfentanil/fentanyl)','Opioid rotation'],
   se:['Constipation','Nausea/vomiting','Drowsiness','Respiratory depression','Pruritus','Urinary retention'],mo:'Pain score. RR. Sedation level. Bowel function. Breakthrough use (indicator of control).'},
  {n:'Diamorphine (heroin) SC/CSCI — palliative',g:'diamorphine hydrochloride',c:'Oncology Supportive/Palliative - Opioid (UK palliative care)',r:'3484',f:['SC/IV powder for reconstitution 5mg/10mg/30mg/100mg/500mg ampoules'],
   pd:'Specialist palliative/paediatric palliative — weight-based',pm:0,pf:'CSCI 24h or SC PRN',pr:'SC/IV/CSCI',pw:'UK only (not available in most countries). High water solubility — ideal for CSCI (concentrated solution in small volume). More potent than morphine (3x by SC/IM route). Conversion: oral morphine ÷ 3 = SC/CSCI diamorphine/24h. Compatible with most palliative drugs in syringe driver (haloperidol, midazolam, cyclizine, hyoscine, levomepromazine). Anticipatory prescribing (end of life — Liverpool Care Pathway successor principles). Licence restricted to UK.',
   ad:'CSCI 24h: [total daily oral morphine (mg)] ÷ 3 = diamorphine mg/24h in syringe driver. PRN SC: 1/6 of CSCI 24h dose.',af:'CSCI 24h; PRN SC 1-4 hourly',ar:'SC/IV/CSCI',am:'Guided by pain control',
   ci:['Respiratory depression (acute)','Raised ICP (relative)'],ca:['Constipation (laxatives)','Nausea','Sedation','Renal failure (accumulate metabolites — consider alfentanil)','CSCI compatibility'],
   se:['Constipation','Nausea','Sedation','Respiratory depression','Pruritus','Myoclonic jerks (accumulation)'],mo:'Pain/comfort score. RR. Sedation level. Bowel function.'},
  {n:'Hyoscine butylbromide (Buscopan) SC — death rattle',g:'hyoscine butylbromide',c:'Oncology Supportive/Palliative - Antimuscarinic (secretions)',r:'6619',f:['SC/IV 20mg/ml ampoule','Oral 10mg tablet (poor SC absorption of oral)'],
   pd:'Specialist palliative',pm:0,pf:'SC PRN or CSCI',pr:'SC/CSCI',pw:'Antimuscarinic — reduces secretions. Palliative care: death rattle (noisy terminal breathing — distressing to family; reposition first; hyoscine reduces secretions). Intestinal colic/bowel obstruction (palliative — spasm relief). Does NOT cross blood-brain barrier (unlike hyoscine hydrobromide — non-sedating). CSCI compatible. Glycopyrronium alternative (similar non-sedating antimuscarinic).',
   ad:'Death rattle: 20mg SC PRN 1-4 hourly. CSCI: 40-120mg/24h. Intestinal colic: 20mg SC/oral TDS.',af:'PRN or CSCI 24h',ar:'SC/CSCI',am:'120mg/24h CSCI',
   ci:['Paralytic ileus (bowel obstruction — relative for spasm)','Myasthenia gravis'],ca:['Urinary retention','Dry mouth','Tachycardia','Does not cross BBB (non-sedating — distinct from hyoscine HBr)'],
   se:['Dry mouth','Urinary retention','Constipation','Tachycardia','Blurred vision'],mo:'Secretion control. Comfort of patient/family.'},
  {n:'Cyclizine IV/SC (palliative nausea/CINV)',g:'cyclizine hydrochloride',c:'Oncology Supportive/Palliative - H1 antihistamine antiemetic',r:'3143',f:['SC/IV 50mg/ml ampoule','Oral 50mg tablet'],
   pd:'2mg/kg/day (max 75mg) SC divided doses',pm:150,pf:'TDS or CSCI',pr:'SC/IV/Oral',pw:'H1 antihistamine antiemetic. Vestibular nausea (motion sickness, post-op). Palliative care nausea (widely used in CSCI). Incompatible with many drugs in CSCI at higher concentrations (particularly diamorphine — precipitates if combined >10mg cyclizine with >10mg diamorphine in 10ml — check compatibility tables). Cardiotoxicity (IV — tachycardia, hypotension — particularly in cardiac failure). Sedating. Antimuscarinic effects.',
   ad:'Nausea: 50mg SC/IV TDS. CSCI: 75-150mg/24h. Oral: 50mg TDS.',af:'TDS or CSCI',ar:'SC/IV/Oral',am:'150mg/day',
   ci:['Severe cardiac failure (relative — tachycardia/hypotension IV)'],ca:['CSCI compatibility (check Twycross table)','Antimuscarinic effects','Sedation','Cardiac effects (IV)'],
   se:['Sedation','Dry mouth','Blurred vision','Urinary retention','Tachycardia (IV)','Constipation'],mo:'CINV control. Sedation level. CSCI compatibility.'},
];

